/* ======================================================
   snippetscpp.js - Construction Phase Plan (CPP) Snippets
   Merged into shared window.SNIPPETS using safe key-assignment
   ====================================================== */
window.SNIPPETS = window.SNIPPETS || {};

window.SNIPPETS["CPP Section 2"] = [
  { title: "2.1 Project Description", content: "The project includes internal improvement works to upgrade the fire performance within The Pines. These works have been recommended by the Joule Group in their 681-DRC-JOU-REP-01-00-FSR Retrospective fire strategy report for disability resource centre document.The full scope of works may be obtained from those drawings provided by the design but, in brief, works include for the enlargement of the existing disabled WC to provide a new wet room, taking space from the adjoining kitchen, alterations to the kitchen including units, sockets and appliances to facilitate the new layout, redecoration, new lighting and new doors. " },
  { title: "2.2 Workplace Statement", content: "The works included within the scope of this project include for the creation, or refurbishment / alteration of a space, or spaces, which would be deemed to be a workplace, as defined by the Workplace (Health Safety and Welfare) Regulations 1992. As such, the finished design must take account of the relevant requirements of the aforementioned regulation." },
  { title: "2.3 Programme", content: "An indicative programme for the proposed project has not yet been provided although the dates and dates for works commencing and concluding on site have not been confirmed. A request for dates was made as part of the RFI issued by Fineline Architectural Design 17 April 2025. As at the date of issue (01) no response to the RFI has been received OR  Prior to works commencing, a construction programme must be produced by the principal contractor and made available to the project team. This must be provided at the earliest opportunity, and any changes to the expected timeframes must be communicated to the client and all other relevant parties at the earliest opportunity." },
  { title: "2.4 Project Notification", content: "The client or Synergize as principal contractor will notify the Health and Safety Executive (HSE) of the project via F10 provided the requirements of regulation 6 of the Construction (Design and Management) Regulations 2015 are met. The client will also manage all subsequent revisions. The principal contractor is to ensure that a copy of the F10 is displayed on site in a prominent location. " },
  { title: "2.5 Existing Records and Plans", content: "Every effort has been made to ensure that the information contained herein and appended to this document is correct and the latest revision. However, those using this information must check with the document author to ensure that they are working to the latest revision." },
  { title: "Existing Records & Plans Table", content: "<table class=\"rte-table\">\n    <thead>\n      <tr>\n        <th>Document Name</th>\n        <th>Location</th>\n        <th>Description</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td>R&D Survey</td>\n        <td>0000_00000_0000_R&D_v1</td>\n        <td>Clarification of ACM in the building</td>\n      </tr>\n      <tr>\n        <td>Add Text</td>\n        <td>Add Text</td>\n        <td>Add Text</td>\n      </tr>\n      <tr>\n        <td>Add Text</td>\n        <td>Add Text</td>\n        <td>Add Text</td>\n      </tr>\n    </tbody>\n  </table>" },
  { title: "Delete Title!", content: "Designers and contractors (including the principal contractor) are to ensure that they have sufficient information to progress with their works without significant unknowns or assumptions. Where this is not possible, they are to make the client and principal designer aware so that they may make the necessary arrangements for further surveys, reports, investigations etc. and distribute that information accordingly.  " }
];

window.SNIPPETS["CPP Section 3"] = [
  { title: "Planning and Managing Construction Work", content: "The principal contractor must ensure that the construction phase plan is issued to the client, principal designer and, where applicable, the CDM adviser to client at least four weeks prior to starting on site to ensure adequate time is allowed for review. The plan must be developed to include information specific to the project together with contractor method statements and risk assessments for the activities to be carried out. <br>Under no circumstances shall construction works commence on site until the construction phase plan has been reviewed and deemed sufficiently developed by the client, principal designer or CDM adviser to client, and permission given, in writing, by the client. <br>The principal contractor must co-ordinate the works with all interfacing workers contractors and affected parties (client staff, members of the public and third parties) to maintain the highest standards of health and safety. Only one principal contractor shall be given responsibility for the co-ordination of health and safety within any site area.  Where such responsibility is not clear e.g., multi tenanted areas with more than one contractor, the situation must be reported to the client." },
  { title: "Safety Goals and Arrangements for Monitoring and Review", content: "<p>The project team aims to achieve the highest standards of health and safety for all personnel, building occupants, members of the public, contractors and suppliers who may be affected by the works.<p><p>The client’s primary objective for this project is to achieve zero harm and zero accidents whereby situations or work activities which may have the potential to result in loss of life or serious injury do not occur. As such, the client shall expect the principal contractor to meet the following minimum standards to assist in achieving these goals:<p><p>Ensure the site is registered with the Considerate Constructor scheme (as applicable)<p><p>3.1.1. Ensure the project is subject to health, safety and environmental audits conducted by internal or external parties, with reports shared with the client, principal designer and, where applicable, the CDM adviser to client.<p><p>3.1.2.\tEnsure all personnel on the project have been assessed and confirmed to hold the necessary skills, knowledge, and experience to undertake the task they have been assigned.<p><p>3.1.3. Ensure all personnel are CSCS card holders (or similar competency scheme provided by others) and copies of cards are obtained, reviewed and kept on file until the project concludes (or longer where required by the client, insurers or the contractors IMS / QMS procedure).<p><p>The pre-construction information has been written in the knowledge that the principal contractor shall have been judged competent by the client to undertake the works required of this project. It is therefore assumed that the principal contractor is fully conversant with all the commonly encountered construction risks, methods and materials and the measures needed to deal with them.<p><p>The principal contractor must be fully conversant with the requirements of the Construction (Design and Management) Regulations 2015, and the duties and responsibilities placed upon them by the same.<p><p>The principal contractor will be responsible for managing the construction works and their management arrangements must be detailed in their construction phase plan. The plan must be site specific and include for all that is required of the construction phase plan as laid out within Appendix 3 of L153 - Managing health and safety in construction.<p><p>The principal contractor must ensure that all contractors’ personnel and those visiting site receive induction training prior to starting work. All contractor personnel will be required to undertake the principal contractor’s induction which will need to include, as a minimum, arrangements for fire, permits to work, site rules and restrictions, accident / incident reporting and emergency procedures. Records must be kept of who has received induction training. The principal contractor must also ensure there are arrangements in place for assessing that site personnel (including visitors) have sufficient training for their needs and are provided with on-site training, through induction, where required.<p><p>The principal contractor must adopt the following good practice guidelines and incorporate them into the site rules.<p><p>3.1.4. Site safety inductions -all site personnel and visitors are to receive a site safety induction from the principal contractor before being allowed onto site (contractors must also provide a site-specific method statement and risk assessment before they can commence works)<p><p>3.1.5. Site storage - only materials of such quantities as are necessary to complete the work in hand are permitted to be stored on site. Storage must be strictly in accordance with the manufacturer’s recommendations. Specific consideration must be given to storage of flammable materials.<p>\t<p>3.1.6. Disposal of waste - it is the responsibility of the principal contractor to ensure that all waste is removed at the end of each work period. Waste must be disposed of in accordance with all current applicable regulations and / or client requirements.<p><p>3.1.7. Nuisance - the creation of noise, dust and any other nuisance is to be controlled and monitored in compliance with statutory requirements and local authority requirements for environmental health, including limits of noise levels and periods of noisy work to be undertaken.<p><p>3.1.8. Neighbours - due consideration must be always given to adjacent occupants and all third parties and their operations. The principal contractor is to liaise with neighbouring owners throughout the construction works.<p><p>3.1.9. Reporting - comply with all requirements for monitoring and reporting as instructed by the client.<p><p>The principal contractor and any contractors with whom they engage must encourage feedback and consultation with their workers in relation to standards of health and safety. Any valid health and safety concerns regarding site conditions must be brought to the attention of the principal contractor’s management team and relayed to the client and principal designer for review and, where required, further action or remedy.<p>  " },
  { title: "Communication And Liaison Between Client and Others", content: "<p>The principal contractor must arrange regular liaison meetings with all associated parties to include frequent progress meetings with the client team to allow for coordination and cooperation from the principal contractor, to ensure all works are completed in a safe and timely manner. It is suggested that these meetings are held no less than monthly. \t\t\n<p><p>It is also envisaged that regular site progress meetings will be arranged to review progress and to discuss any issues arising at that time in the construction programme, or since the last progress meeting. The principal contractor and their design team (or designers under their direction) are to take a proactive approach to informing the principal designer of any significant design changes, or elements of design to be undertaken by contractors not known to the principal designer.\n<p><p>The principal contractor shall also ensure that all workers are provided with a suitable, site-specific induction to inform them of the arrangements for health, safety and welfare which must include any relevant findings resulting from risk assessments, including risks arising from activities of other operatives working nearby or members of the general public. Site rules must be explained along with the procedures to be followed in the event of any worker finding themselves in a position of serious and imminent danger. \n<p><p>The principal contractor shall ensure that arrangements are in place for worker engagement on site and where necessary make special arrangements for workers for whom English is a second language, or who are unable to read English and/or have literacy difficulties. These could include provision of translation, use of interpreters or replacing written notices with clearly understood symbols or diagrams.\n<p><p>The principal contractor shall implement and maintain arrangements to enable effective co-operation and consultation between themselves, contractors, and workers. Arrangements made in respect of co-operation and consultation with workers on site must be recorded by the principal contractor and included in the construction phase plan. Such arrangements will require regular review and updating as circumstances on site change. Such arrangements need to cover all workers effectively, including those who may only be on site for brief periods and must be proportionate to the size and complexity of the work, the scale of hazards and the size of the workforce." },
  { title: "Site Security", content: "<p>The principal contractor must ensure that no unauthorised persons obtain access to the site areas under their control, in accordance with Regulation 13(4)(b) of the Construction (Design and Management) Regulations 2015, and that any notices required to be displayed are maintained in a legible condition where they can be readily seen by any person on the site.\n<p><p>The principal contractor shall ensure the site is secured from third parties and that such arrangements are maintained throughout the construction works as far as is reasonably practicable, whilst also ensuring the security of adjacent premises are not prejudiced due to the works, and that any temporary working platforms and/or scaffolding are designed with this in mind. The means of securing the site shall be carefully selected by the principal contractor following a thorough risk assessment undertaken by the principal contractor which considers site constraints, surrounding land and building uses, those persons in and around the site and the general topography and site levels.\n<p><p>Where fencing, hoarding, barriers or similar are selected the principal contractor must ensure that all relevant temporary works designs are in place prior to erection, and that said temporary works are effectively managed via a coordinator, supervisor and the presence of a temporary works register which must be kept up to date.\n<p><p>The principal contractor’s temporary works provisions must be detailed within their construction phase plan and, where appropriate, the design team including principal designer and (where applicable) adviser to principal designer must be given the opportunity to review and comment on any temporary works provisions including design.\n<p><p>The principal contractor shall also ensure that there is an appropriate system in force for ensuring the health and safety of all those who visit the site which must include control of access points, recording of visitors/operatives to and from the site, means of identification and site induction.\n<p><p>All such access and security arrangements shall be agreed in advance with the client and be included within the principal contractor’s construction phase plan prior to commencement of works on site.\n<p><p>It is anticipated that a secured area will be located around the boundary of the site and the compound with careful management of the public where necessary.<p>" },
  { title: "Welfare Provisions", content: "<p>The principal contractor shall ensure that adequate welfare facilities are provided prior to the start of any construction work and are in accordance with Schedule 2 of the Construction (Design and Management) Regulations 2015. Full details of the welfare facilities proposed must be included in the principal contractor’s construction phase plan. Failure to do so will prevent the client from giving permission for construction work to commence. Minimum requirements include:<p><p>The principal contractor shall ensure that adequate welfare facilities are provided prior to the start of any construction work and are in accordance with Schedule 2 of the Construction (Design and Management) Regulations 2015. Full details of the welfare facilities proposed must be included in the principal contractor’s construction phase plan. Failure to do so will prevent the client from giving permission for construction work to commence. Minimum requirements include:\n1.\tToilets\n2.\tWashing facilities (including showers if considered appropriate)\n3.\tHot and cold running water\n4.\tDrying rooms\n5.\tLockers\n6.\tMess room\n7.\tDrinking water\n8.\tA means of heating food\n9.\tA means of boiling water \n<p>All facilities are to be accessible and shall have adequate heating, lighting and ventilation, whilst in addition the principal contractor shall also consider the following:\n1.\tIdentifying the site access route to the welfare provision and site offices – signposting\n2.\tThe supervision of persons arriving at the site whilst avoiding people crossing the site unnecessarily\n<p><p>Adequate first aid facilities shall also be provided and maintained on site and at least one trained first aider is to be in attendance during site hours. Compliance shall be in accordance with The Health and Safety (First Aid) Regulations 1981. Provision of welfare must be in line with HSE publications INDG293 ‘Welfare at work Guidance for employers on welfare provisions’ and CIS59 ‘Construction Information Sheet No 59 ‘Provision of welfare facilities during construction work.’\n<p><p>The principal contractor shall be responsible for arranging temporary water, electric or drainage facilities etc., and all arrangements must be agreed with all relevant parties i.e. client, landowner, managing agent, developer and statutory authorities.<p>\n " },
  { title: "Transport Arrangement and Restrictions", content: "<p>The principal contractor shall ensure that sufficient traffic management provisions are in place to allow construction / delivery vehicles to enter, unload / load and exit the site without causing any risk or disturbance to neighbouring premises and transport networks. Access roads and routes to and within the site must not be restricted or interrupted at any time without confirmation from the client or any other interested parties i.e. Highways England, local authorities, adjacent properties / operators. \n<p><p>A detailed traffic management plan must be put in place prior to works starting on site and shall conform to the requirements of Regulation 27 of the Construction (Design and Management) Regulations 2015. This is to be determined by the principal contractor during the design phase and details of the traffic management plan must be included in the principal contractor’s construction phase plan at the outset and must be continually developed as work progresses on site. \n<p><p>The principal contractor’s construction phase plan must detail the arrangements for the delivery and removal of plant and materials from the site. Access roads and routes to and within the site must not be restricted or interrupted at any time. It is of particular importance that the access roads are not obstructed during peak hours. Routes within the site area shall also not be obstructed or interrupted at any time.\n<p><p>The principal contractor must agree all site transport arrangements, site access and all vehicular access routes prior to commencing works on site. In compiling the traffic management plan the principal contractor must note traffic and parking restrictions on the approach roads to the entrance to the site and consider the following:\n1.\tPedestrian areas and footpaths.\n2.\tBus lanes and cycle lanes.\n3.\tParking of Contractor’s vehicles must not be allowed to restrict routes.\n4.\tAccess for the emergency services will be required to be maintained at all times.\n5.\tSpeed restrictions.\n6.\tNo entry of vehicles\n<p><p>The principal contractor must also take into consideration the health and safety implications posed by variations in the traffic systems on the surrounding roads and in this respect the following is a list of items for consideration although this is merely indicative and must not be considered exhaustive:\n1.\tJunctions\n2.\tPedestrian crossings\n3.\tAccess and egress routes\n4.\tDeliveries to adjoining units\n5.\tPeak traffic times in the immediate vicinity\n<p><p>Public walkways should not be obstructed where it is possible, if pedestrians are forced into the road, then barriers and signage must be in place in accordance with the New Roads and Street Works Act chapter 8 requirements and directing them safely around the area. Deliveries must be pre-programmed with the site manager.<p>" },
  { title: "Clients Permit to Work System", content: "<p>The client operates a comprehensive permit to work system. High risk activities will require a permit to work before work can proceed. It must be noted that there are also many other indirect activities that may create hazards for others e.g.\n1.\tFlammable and explosive materials\n2.\tInert gases\n3.\tToxic gases\n4.\tCorrosives\n5.\tBreaking into pressurised systems\n6.\tMechanical and electrical hazards\n7.\tExcavation works\n8.\tMovement of vehicles\n9.\tBreaches to fire compartmentation\n<p><p>The client’s permit to work does not exclude the principal contractor from managing their own permit to work system but must be used to supplement the client’s own as opposed to replacing, i.e. the client may issue a week long permit for roof works, the principal contractor may issue a daily permit in addition to this. If this is to be the case it must be detailed in the principal contractor’s construction phase plan. \n<p>\n    OR \n    \n    <p>The client has confirmed that the area affected by the proposed works are under the control of the principal contractor only and they shall be responsible for the issuing of permits for high-risk activities as they see appropriate. The permit to work system must be detailed in full in the principal contractor’s construction phase plan.<p>" },
  { title: "Fire Precautions", content: "3.7.1.Fire Emergency Plans & Arrangements: HSG 168. Emergency plans work best when standard symbols are used as per the ISO safety signs and signals regulations. It allows all workers of all nationalities to see and note familiar symbols such as the running man exit signs, red fire extinguisher signs etc." },
  { title: " 3.7.2", content: "Fire Prevention of significant importance where the building is operational: Contractors are responsible for providing and maintaining fire precautions to safeguard staff and visitors to the construction site at all times. As well as following the requirements under the other Fire Prevention headings, the principal contractor must consider the use of Wireless sounder system if/as relevant to the improvement of raising the alarm on each ﬂoor level if more than one floor. The Protocol for raising the alarm must also be arranged when working near other businesses, residential apartments and shared fire exit routes." },
  { title: "3.7.3", content: "Please also note that dust levels will need to be minimised using appropriate techniques and included in the Principal Contractor’s Construction Phase Plan. This is to ensure that any fire detection/alarm system which is to remain active is not adversely affected by dust." },
  { title: "3.7.4", content: "Existing untested fire precautions: Any fire / smoke detection which remains from the client is considered to be untested until proven otherwise. It is also noted that regardless of testing status, any existing provisions should not be relied upon for the purposes of fire safety as site conditions are to change, meaning detection is unlikely to cover the full extent of the building as the project progresses." },
  { title: "3.7.5", content: "Precautions & Means of Escape:  Under no circumstances shall the means of escape from this building be obstructed unless alternate means are provided, & the means are communicated to all those parties who may be affected. Any alternate means of escape must be suitably lit, signposted & all staff & building users notified prior to any obstructions/alterations being undertaken. The route must be sufficient in width for the number of persons proposing to escape. Equally, no works shall be undertaken in or around any means of escape used by other units." },
  { title: "3.7.6", content: "A fire & emergency plan for the Construction Phase must be developed by the principal contractor, in compliance with the Regulatory Reform (Fire Safety) Order 2005, HSG168 Fire Safety in Construction (3rd Edition July 2022) and The Joint Code of Practice on the Protection from Fire of Construction Sites and Buildings Undergoing Renovation (10th Edition January 2023). However, the principal contractor must enquire if there is a Fire Emergency Plan in place on site & this must be taken into consideration when devising their own Plan for the construction works, which must establish the risks, escape routes & fire precautions." },
  { title: "3.7.7", content: "The principal contractor must review their Emergency Plan & Fire Risk Assessment & frequent meeting must take place between the principal contractor & building manager to discuss the works to communicate & coordinate emergency fire procedures (methods of raising the alarm & how the site will be protected) especially where fire detection & alarm systems are isolated due to the works." },
  { title: "3.7.8", content: "Arrangements MUST be in place for: \n1.\tThe appointment of a designated & adequately qualified Fire Marshall for the construction site\n2.\tAppropriate notices, temporary signage, emergency lighting, detection, means of raising the alarm, means of escape, a place of total safety, provision of portable fire-fighting equipment, training, & practice drills, which shall be recorded. \n3.\tSite inductions for all persons working on or visiting the site\n4.\tReviewing the plan regularly to ensure they are applicable throughout the project\n5.\tThere must be provision for raising the alarm in adjoining operational areas (if relevant.)\n6.\tLone working & work in remote locations must be considered.\n7.\tAny persons affected by the works must be made aware of the plan.\n8.\tUnder no circumstances shall escape routes from any part of the site be obstructed without the provision of alternative means of escape & provision of sufficient information to all on site. \n9.\tThe means of escape from the building in or on which the works are to be carried out must be maintained throughout the duration of the works & be amended as necessary as the work progresses. \n10.\tWhere scaffolding & access equipment is used, it must be designed, constructed, & used to permit escape via a sufficiently wide pedestrian route clear of obstructions & within acceptable travel distances." },
  { title: "3.7.9", content: "Fire Compartmentation:  Fire compartmentation is an important element of ‘passive fire protection’ & is achieved by dividing the premises into ‘fire compartments’ through the use of fire doors, floors & walls of fire-resisting construction, cavity barriers within roof voids & fire stopping to services that penetrate through these dividing elements must be provided to any & all openings or breakthroughs." },
  { title: "3.7.10", content: "Where an escape route needs to be separated from the rest of the premises by fire-resisting construction e.g., a dead-end corridor or protected stairway the following compartmentation should be ensured:\n1.\tDoors (including hatches to cupboards, ducts & vertical shafts linking floors), walls, floors & ceilings protecting escape routes should be capable of resisting the passage of smoke & fire for long enough to enable people to escape the building\n2.\tWhere suspended or false ceilings are provided, the fire resistance should extend up to the floor slab level above\n3.\tCavity barriers, fire stopping & dampers in ducts should be appropriately installed.\n4.\tAny holes penetrating a compartment wall must be made good by the contractor prior to the completion of works.\nThe above requirements must meet the following criteria\n1.\tInstallation of fire doors to BS 476 Part 22\n2.\tFire stopping to BS 476 Part 24\n3.\tFire compartmentation to BS9999" },
  { title: "3.7.11", content: "Fire Prevention, Fire Risk Assessments, Fire Marshal etc: Emergency Plans and FRA’s MUST be prepared and regularly reviewed to ensure they are applicable to the circumstances throughout the project. Where there is a Fire RA and Plan on site, the principal contractor shall take note in determining their own FRA for the works. The FRA must include for phased works which may include Fire Exits out of commission or exits from one floor to another due to Principal Contractor’s works; how will the Principal Contractor liaise with the building management and vice versa, should a fire develop in either the CDM Works area or other areas of the building (e.g.) fire separation (fire wall.)  Compliance with  Select Regulation must be maintained at all times and reference made to the Third Edition of HSG168. Fire safety in construction - HSG168 (hse.gov.uk). The Principal Contractor must strictly adhere to any arrangements in place for handing over responsibility for the work areas and escape routes each day. Where the building will be in operation during the works, any areas affected by the works or access to the work sites must be effectively separated from the daily operations." },
  { title: "3.7.12 Regulation 38 declaraiton", content: "Regulation 38 Declaration:  The aim of Regulation 38 of the Building Regulations 2010 (as amended) is to ensure that the person responsible for the building has sufficient information relating to fire safety to enable them to manage the building effectively. Compliance with Regulation 38 will be achieved when the person responsible for the building has all the information to enable them to do all of the following. \n1.\tUnderstand and implement the fire safety strategy of the building\n2.\tMaintain any fire safety system provided in the building\n3.\tCarry out an effective fire risk assessment of the building\nWhere other units are interlinked and/or include zoned fire detection / alarm systems and strategies, the information must reach the person responsible for the building; this may be (e.g.)  the Landlord or Management company and the client is reminded that the information gathered from the principal contractor that forms the 3 points above may be required to be included into a wider fire strategy for the whole structure. Regulation 38 puts onus on the person carrying out the work to give fire safety information to the responsible person no later than the date of completion of the work, or the date of occupation of the building, whichever is the earlier. Please note a copy of the declaration has been included in the pre-construction information pack for your reference if required for the works carried out for this project." },
  { title: "3.8 Accident and Emergency Procedures", content: "The principal contractor is to ensure they confirm all accident and emergency policies and procedural requirements with the client prior to construction works commencing and fully comply with them once works are underway. Where present, these must be detailed briefly in the principal contractor’s construction phase plan to demonstrate that safety management provisions on site reflect the requirements. All accidents, dangerous occurrences etc. must be notified to the client and, where applicable CDM adviser as soon as is practicable to do so. The principal contractor must prepare, implement, and review emergency procedures, H&S reporting and H&S liaison procedures and include all such information in the construction phase plan. All accidents and incidents must be reported and recorded. The client, principal designer & CDM adviser must be notified by the most immediate means as soon as a reportable accident or dangerous occurrence has occurred.\nThe principal contractor shall describe the arrangements for reporting and investigation of accidents including near misses within their construction phase plan.  \nSite specific emergency procedures shall be detailed in the principal contractor’s construction phase Plan and shall include (but not be limited to) the following:\n1.\tLocation and telephone number of the local hospital accident and emergency department\n2.\tLocation and telephone number of the local police station\n3.\tLocation and telephone number of the local fire and rescue station\n4.\tEmergency telephone numbers for the various statutory utilities\n5.\tThe telephone number of the Environment Agency (in the event of an environmental emergency)\nThese arrangements shall be communicated to all operatives and visitors, whilst the principal contractor shall also ensure the adequacy of the procedures adopted are reviewed as works progress. The site emergency routes and exits shall be marked on a plan of the site and all emergency routes are to remain open throughout the duration of the works. An emergency first aid notice shall also be displayed in a prominent position on site.\nThe principal contractor must give advanced notice to the client and adjacent neighbours of any required impairment to access routes and must co-operate in the necessary arrangements and precautions. Emergency procedures must be agreed before starting any construction operations." },
  { title: "3.9 Site Rules and Restrictions", content: "It is expected that any client site requirements shall form the basis of any site rules, with the principal contractor able to implement their own site rules provided they do not contradict or impede on those of the client. Site rules and restrictions must be agreed with the client prior to works commencing on site. A building specific induction will be required prior to the commencement of works. Where applicable, please refer to those persons (client) detailed in the project directory to arrange for site inductions. The principal contractor site rules are to be included within their construction phase plan and take account of the information provided within this document and its appendices in relation to the protection of site operations." },
  { title: "3.10 Confined Spaces", content: "Where works are to be undertaken within, or to form confined space(s), the principal contractor must refer to the Confined Spaces Regulations 1997 and prepare the necessary RAs and Permits to Work. For instance, service corridors may be included in the build and dependant on construction methods, may become confined/enclosed spaces. if this should happen, the Principal Contractor must refer to the Confined Spaces Regulations 1997 and prepare the necessary risk assessments and permits to work." }
];

window.SNIPPETS["CPP Section 4"] = [
  { title: "Delete title !", content: "Hazards referred to in this section are either known to be present or are suspected to be present. The principal contractor must ascertain for themselves any further information they may require ensuring the safety of all persons affected by the works:" },
  { title: "4.0 Boundaries and Access", content: "The site boundary is to be confirmed on site with the client, and will be determined, in part, by the finalised design and any potential phasing requirements. Any areas used externally to facilitate the works, such as a defined compound and/or materials area shall also be considered to be within the ‘CDM area’ for the purposes of this project. \nAccess shall be determined closer to start on site and shall be agreed with the client. \nThe principal contractor must ensure that access for emergency vehicles, e.g., fire appliances and ambulances remain free from obstructions throughout the construction period. The principal contractor will need to arrange a suitable area to be allocated for the parking of contractors’ vehicles and a suitable area for the secure site accommodation and storage of plant and equipment.\nThe principal contractor in line with their respective construction phase plan will be required to develop a coherent traffic management plan.\nThe principal contractor shall ensure that a sufficient pedestrian, traffic, and logistics plan is in place to allow construction / delivery vehicles to enter, unload / load and exit the site and for the movement of personnel and materials through the building and site without causing any risk or disturbance to the existing neighbouring premises or road infrastructure.\nStorage of materials must be within a designated area within a secured site compound as indicated in the Construction Phase Plan, any generated waste, combustible, and flammable materials / substances must be suitably removed from site as early as possible.\nWhere roads or pavements need to be obstructed for skips, building materials, scaffolding, and hoarding, crane, or access platforms etc. the principal contractor will be required to obtain the necessary licences and permits." },
  { title: "4.1 Deliveries and Waste Collection or Storage", content: "The principal contractor must confirm storage and waste skip locations with the client prior to works commencing. Waste skips must be fully covered and lockable. The skips must be located a sufficient distance from both permanent and temporary buildings to prevent heat transfer in the event of a skip fire. \nRecommendation: The principal contractor is advised to check with their insurer to see if there is any stipulation in the schedule of insurance relating to fire, skips and waste.\nIn accordance with environmental legislation, all waste generated from the works shall be, where practicable, segregated and disposed of to a licensed tipping facility utilising registered and licensed waste disposal contractors. \nA site waste management plan must be in place prior to works commencing and all waste removed from site must be recorded and the plan retained for two years following practical completion. In the case of hazardous waste, all products shall be removed and disposed of in accordance with relevant local enforcing bodies, whilst all licenses and transfer notes obtained shall be retained as proof of correct disposal.\nSuch arrangements as identified above shall be included within the principal contractor’s construction phase plan and shall also detail arrangements for storing (including the provision of suitable and sufficient areas to accommodate all plant, equipment, and materials out of working hours as appropriate), removal and the location of skips – Generally:\nAll concrete and non-impacted pipework (where applicable) to be recycled, where possible.\nAll waste transfer and consignment records to be maintained and kept on site.\nSoils (Where applicable) to be disposed of to an appropriately licensed facility.\nWater to be either disposed of via the foul sewer using a discharge consent and pre-treated prior to disposal.\nTanking-off-site may also be required.\nOdours and dust from stockpiles will need to be managed.\nResults of monitoring for dusts and vapours not to exceed set targets.\nStorage of materials must be within a designated area within a secured site compound as indicated in the construction phase plan, any generated waste, combustible, and flammable materials / substances must be suitably removed from site as early as possible." },
  { title: "3.2.\tAdjacent Land Uses", content: "Add text" },
  { title: "3.3.\tExisting Storage of Hazardous Materials", content: " Due consideration must be undertaken whilst on site and works stopped if suspected hazardous materials over and above those highlighted above, and report this directly to the client." },
  { title: "3.4.\tLocation of Existing Services", content: "Click to add data\nThe principal contractor must satisfy themselves that the information provided by the client and design team is correct, with validation via ground penetrating radar, tracing or similar prior to works commencing.\nDue to the nature of the works, the isolation of client services Choose an item. be required. The principal contractor is to confirm with the client all procedures in relation to isolation of services prior to commencement of works on site.\nThe principal contractor will need to provide details of their intended procedures for the protection and decommissioning (where applicable) of mains and services. Any works to or around live services must be completed under appropriate safe system of work provision with appropriate given notices for any required shut down periods. \nAny anticipated requirements must be identified and agreed following consultation with the public utilities’ provider and the client, project manager and principal designer.\nWhere necessary the principal contractor shall liaise with all relevant public utilities and observe all prescribed recommendations, bye laws or regulations for work adjacent to existing services. Notification must also be given to all utility companies and / or adjacent owners of any works to existing services (particularly those which require a temporary shutdown) in advance of such operations commencing.\nAll survey information is to be used when planning any work to be done which involves excavation. All work must be carried out in accordance with HSG47 Avoiding Danger from Underground Services and GS6 Avoiding Contact with Overhead Lines." },
  { title: "3.5.\tGround Conditions", content: "Add text" },
  { title: "3.6.\tExisting Structures", content: "The design team and principal contractor must satisfy themselves that they have sufficient information to progress with their design and demolition / construction and where assumptions have been made due to a lack of information, these must be highlighted on drawings, specifications, scope of works etc. or within the CDM risk register." },
  { title: "3.7.\tBuilding Plant & Equipment", content: "It is the responsibility of the design team and contractor team to review that information which is available and advise where further information is required which is not available." },
  { title: "3.8.\tAsbestos (as per defined project CDM Area)", content: "Click to add data\nAsbestos waste is to be disposed offsite by a licensed carrier to a registered site with all waste transfer, consignment notes and relevant documentation retained for handover. \nThere is a duty to report immediately any suspected asbestos containing materials. These suspected materials are not to be disturbed. The principal contractor is to take necessary precautions to protect their workers and other affected parties form exposure to asbestos. If the presence of asbestos is suspected, the contractor must stop work immediately and secure the area and advise the client who will agree with the principal contractor any necessary investigations and remedial works.\nThe principal contractor must ensure that all staff who may encounter asbestos during their work have received the relevant level of accredited asbestos awareness training and training is up to date. \nThe building was built post 2000, circa ____ therefore it is unlikely that the building/CDM area will contain ACMs within the structure.\n \nOR The building was constructed pre-2000, circa ___) OR date (____) & there is the possibility of Asbestos Containing Materials (ACM’s) within the structure.\nSurvey Status: Choose an item.\nWhere the date of build is unknown, the principal contractor must satisfy themselves of status if considered relevant to the project and the following cautionary information must be noted.\nGeneral Note\nThere have been reported incidents within the UK where asbestos containing materials have been found in imported goods installed within a property, or where the building was constructed on or around the year 2000.  As such, whilst a refurbishment survey may not be required, the principal contractor must ensure that they and any sub-contractors with whom they engage have suitable & sufficient asbestos awareness training & that procedures are in place for the discovery of suspicious materials, including for ceasing works, surveying, & suitable removal and/or encapsulating.\n1.\tIf relevant to the works & if/when available, please ensure that all operatives are shown where they can find asbestos registers/reports in the site file and ask that they sign to confirm they have seen & read them. This could be included in the induction attendee list, but it must be clearly stated that they have read the asbestos reports & understand the content\n2.\tThe principal contractor's construction phase plan must include arrangements if coming across previously unidentified asbestos containing materials e.g. removing everybody from the area and cordoning off until it has been confirmed that it is safe to return. This may be in the form of e.g. written confirmation or (if relevant) air clearance certificates.\n" },
  { title: "3.9.\tContaminated Land", content: "Add text" },
  { title: "3.10.\tHealth Risk Arising From Clients Activities", content: "Add text" },
  { title: "3.5.\tGround Conditions", content: "Add text" },
  { title: "3.5.\tGround Conditions", content: "Add text" }
];

window.SNIPPETS["CPP Section 5"] = [
  { title: "5.0.\tDesign Assumptions and Control Measures", content: "The designs provided by the design team assume that the principal contractor and other contractors are competent, that they will take note of the issues included in this document, that good industry practice and safe working procedures will be adopted. Notes on relevant drawings and hazard registers /schedules are the primary means of presenting key risk related information to others, including designers and contractors, who will need the information in order to identify and manage risks." },
  { title: "5.1.\tDesign Changes", content: "Following the appointment of a principal contractor, the principal contractor shall liaise with the principal designer to review progress and the development of the CDM risk register and designers’ risk assessments found in Appendix X.\nThe principal contractor is to inform the principal designer in advance of any design work that is to be carried out by them, their appointed design team, or other contractors during the construction phase. Such work may include engineer-designed temporary works, e.g., falsework or scaffolds, designed by specialist contractors and the design involved in changes or contract variations.\nThe principal contractor is to ensure that:\n1.\tAll such design is prepared in accordance with CDM Regulation 9 and follows the principles of prevention.\n2.\tThe principal designer is given the opportunity to attend all design team / review / workshops and meetings.\n3.\tDesign risk management output and other health and safety information resulting from the design is passed to the principal designer for review and comment, prior to any decision to proceed with the related construction work.\n4.\tThe information is provided in line with the above \nDuring the construction phase the principal contractor is to inform the principal designer of:\n1.\tAny unforeseen eventuality resulting in a substantial design change.\n2.\tAny proposal to depart from the design or assumptions set out in the tender proposals.\n3.\tAny change likely to affect information for inclusion in the health and safety file.\nThe principal contractor must effectively monitor construction progress and notify and agree with the principal designer any such proposals or changes, to the extent that they affect health and safety information, prior to their implementation. The principal designer must be informed of all proposed design changes prior to their implementation and will advise on any CDM implications." },
  { title: "5.2.\tSignificant Health & Safety Risks Identified During Design", content: "For full details of significant risks identified during design please refer to the CDM risk register which is appended to this document and can be found within Appendix X.\nThe principal contractor must also hold regular risk workshops or similar to communicate the information to the workforce and ensure that safe methods of work are produced for dealing with the risks." },
  { title: "5.3.\tMaterials Requiring Particular Precautions", content: "There may be materials incorporated in the works which are subject to the requirements of the Control of Substances Hazardous to Health Regulations (COSHH) and in these instances the principal contractor and any contractors with whom they engage shall perform risk assessments for hazardous materials. The principal contractor must coordinate this process.\nCaution must also be exercised when handling the various hazardous substances which are commonly used and, in these instances, the principal contractor shall ensure that Material Safety Data Sheets (MSDS) are available and COSHH assessments undertaken. \nThis information must be read and understood, and all control measures described within the COSHH assessments implemented. Activities involving materials which are hazardous to health will need to be assessed and method statements established prior to works commencing.\nThe Dangerous Substances and Explosive Atmospheres Regulations (DSEAR) aim to protect people from the risks from fire, explosion and other similar events that may occur as a result of the presence or use of dangerous substances. DSEAR is principally concerned with the safe use of substances that can create thermal radiation effects (burns) and over-pressure effects (blast injuries). \nIn summary a dangerous substance is any natural or artificial substance which is explosive, extremely flammable, highly flammable or flammable, including liquids, vapours, gases, dust and equipment that might leak or generate a dangerous substance. \nSuch substances that are bought in commercially will be recognised by the standard pictograms on the container, e.g. Explosive – Oxidising – Flammable." }
];

window.SNIPPETS["CPP Section 6"] = [
  { title: "Delete !", content: "It is the legal responsibility of the principal contractor to ensure that the construction phase plan includes the information specified in the Construction (Design and Management) Regulations 2015, and Appendix 3 of L153 - Managing health and safety in construction. If the plan does not contain this information, then the principal contractor cannot legally commence work on the site and any resulting delays will be the responsibility of the principal contractor. Any queries on this must be addressed promptly to the principal designer and, where applicable, CDM adviser.\nA programme for the review of the construction phase plan with due time for review must be established with the principal designer and, where applicable, CDM adviser in advance of the works, a minimum of four weeks for review prior to starting on site must be allowed.\nThe construction phase plan must be concise, focused and project specific, respond to issues raised in the pre-construction information and address key hazards and restrictions. Generic or policy-type statements are not acceptable." }
];

window.SNIPPETS["CPP Section 7"] = [
  { title: "Delete!", content: "6.0.\tFormat\nA health and safety file will be required within 4 weeks of practical completion of the project and be restricted to all relevant information associated with the works, drawing attention to any residual risks that could not be otherwise addressed, and provided in sufficient detail that will enable all persons who subsequently clean and maintain the premises and installations to adequately manage those risks.\nAll parties must provide the principal designer with those documents which will form part of the health and safety file in a format which does not require further amendment before inserting into the file. The document originators are responsible for the accuracy of the information provided.\nThe health and safety file shall be delivered in an electronic format incorporating .pdf copies of documents and where specifically requested by the client, .dwg or similar for drawings, models and the like. \nAs outlined above these documents must be passed to the principal designer for their review, and confirmation that they appear sufficient to comply with the requirements of the health and safety file prior to the completion of the works and with sufficient time to allow for review, amendment and re-issue. \nThe electronic health and safety file must be completed two weeks prior to handover. The principal designer will audit the file during this time. All parties must complete any outstanding information two weeks after practical completion.\nContents of the health and safety file shall form a separately identifiable volume / section if combined with the operation and maintenance manual. Where information needs to be incorporated into both the health and safety file and the operational and maintenance manual it will be sufficient that a cross reference is included. All documents included in sub sections must be accompanied with a register of that section’s contents. \nNOTE: Fineline Architectural Design Limited do not provided paper copies of the health and safety file unless this has been specifically requested by the client on instruction, and a fee has been agreed.\n6.1.\tContent \nThe health and safety file will contain the following information and aligns with that which is required of a health and safety file under Appendix 4 of L153 - Managing health and safety in construction. Any queries on this must be addressed promptly to the principal designer and, where applicable, CDM adviser:\n1.\tGeneral information – Introduction and legislation\n2.\tProject details - Brief description of the works; Design discipline statements; Project directory\n3.\tResidual hazards\n4.\tKey structural principles\n5.\tAny hazards associated with materials used\n6.\tPlant and equipment replacement strategies including information relating to future demolition\n7.\tAccess cleaning and maintenance strategies\n8.\tServices’ details (including firefighting)\n9.\tInformation and as built drawings of the structure" }
];

window.SNIPPETS["CPP Section 18"] = [
  { title: "7. Appendices", content: "\n1.\tAppendix A :  \n2.\tAppendix B : Underground Services Drawings \n3.\tAppendix C  : Approved Traffic Management Plan\n4.  Appendix D  : Site Rules" }
];

window.SNIPPETS["CPP Section 2.1"] = [
  { title: "2.1 Description of Works", content: "This project is split into 3 individual phases, Phase 1 will be to deconstruct and clear the whole area in preparation for the phase 2 and eventually Phase 3 works which are to construct 147 residential homes. This Construction Phase Plan (CPP) has been developed for the Phase 2 works only which are detailed as follows: Phase 2 – Construction of Roads and Sewers will focus on establishing the site infrastructure, main drainage, and road formation up to binder course level. This phase also includes the installation of key utilities, initial safety measures, and essential enabling works to support future construction phases. All works will be carried out in accordance with approved drawings, specifications. General ground works, Elements of the substructure, drainage, and external finishes required to prepare each plot and surrounding areas for the subsequent build stages. Activities will be carried out in accordance with the issued construction drawings, engineering layouts, and specifications " }
];

window.SNIPPETS["CPP Section 3.1"] = [
  { title: "3.1 Location of The Site", content: " The site is located on the eastern edge of the village of Keyingham, approximately\n14km to the east of Hull City Centre. It is centred at National Grid Reference (NGR)\n525182mE, 425370mN. A site location plan is presented as Figure 49885/001.\n2.2.2 The site is irregular in shape, covers an area approximately of 4.35ha and gently\nslopes to the south towards Ottringham Road along with the surrounding area " }
];

window.SNIPPETS["CPP Section 3.2"] = [
  { title: "3.2 Planning Restrictions", content: "Permitted Working Hours: \nNot before 7:30am or after 18:00pm Monday to Friday\n- At no time on Saturdays, Sundays or Bank Holidays unless agreed by the Client.\n- Nothing specific regarding deliveries but care to be taken to have deliveries outside school times\nwhere possible. \nMinimum mobilisation period for preparation and planning: 4 Weeks.\nNo Works will commence until the local authority and client have approved in writing details of the layout, drainage, construction, utilities & lighting." }
];

window.SNIPPETS["CPP Section 3.3"] = [
  { title: "3.3 Existing Services", content: "The known extent of existing mains/services comprising, water & fire main, electricity, gas, drainage, and telecommunication services on, or adjacent, to the site are detailed in the Included Appendix B which will be held alongside this document and held by the Prestons senior management team on site. Contractors must verify both the accuracy of service drawings ensuring all such services are traced using electromagnetic and/or ground penetrating radar detection systems, status verified, shut down and isolated or marked up and protected prior to commencing any works and for liaising with Prestons Construction Limited (PCL) at all times. Permits are required for excavation as instructed from the PCI. All newly installed services must be included on updated service plans, and  by any previously Phased works in this instance this is from the demolition phase. Information will be requested from the Principal Designer for the location of any services likely to be present and not recorded on the utility drawings in the Pre Construction Information (PCI). All services uncovered are to be treated as live unless they have been confirmed otherwise by the utility services with any unrecorded services immediately brought to the attention of PCL Management.Particular attention will be given to the presence of existing services in relation to providing a new supplies/substation for the project i.e. all works to be carried out strictly in accordance with HSE Guidance HS (G) 47/Local authority/clients instructions & PCL safe systems of work;  with a particular emphasis on pre-planning the works and providing competent supervision and workforce to manage the works.Appropriate controls will be identified in the method statement and risk assessment and must be implemented when services are made live e.g. isolation, warning signage, and permit to work system.It may from time to time during construction phases that various existing live services will be present. Any work that may undermine or disturb any existing service contractors must establish and agree with PCL what protection or control measure must be employed before work commences. Every effort must be made to avoid digging near any live underground services " }
];

window.SNIPPETS["CPP Section 3.4"] = [
  { title: "3.4 Existing Drawings and Documentation", content: "The Pre Construction Information (PCI) has been provided by the client and Principal Designer and is available in the project Central Data Environment Key documents spcific to the Phase 2 works have been appended into this CPP and will be made available to all contractors under the control of PCL. " }
];

window.SNIPPETS["CPP Section 3.5"] = [
  { title: "3.5 Existing Traffic systems and Traffic Management Planning", content: "The Traffic Management Plan referenced in the Pre Construction Information Plan (Drw Ref: 3175-01-04) will be used as approved by the local authority and included in Appendix C.\n   The Traffic Management plan and access and egress routes will be kept under review and made available to all contractors/vistiors to site by displaying this inside the site office. This plan will alos form part of the site induction that every contrcator/visitor will undertake. \n   The Traffic management Plan will include as a minimum: \n   Access/egress routes\n   Traffic speeds/limits\n   Loading and unloading areas\n   The Site layout (phased)\n   Pedestrian routes and crossings\n   Signage\n   Width and height restrictions due to overhead cables, etc\n   Parking\n   Arrangements for delivery, unloading, and disposal of waste require careful planning and programming. Contractors must liaise with the PCL senior site manager or their nominee to enable effective co-ordination. The arrangements provided must be included within the contractor’s method statements. Strict controls will be enforced, and contractors must give a minimum of 48 hours’ notice of deliveries and/or collections. All deliveries are to have a suitably trained banksman. The queuing of site delivery vehicles, plant, etc. on the public highway is not permitted. In addition to these controls, the local authority may have their own parking and unloading restrictions that has not previously been identified in the PCI which cannot be managed at this time. Contractors must ensure that their plant and delivery vehicles are adequately controlled at all interface areas with the public, existing offices, and businesses, eliminating risks to others and minimising inconvenience to pedestrians and highway users. Contractors must ensure their suppliers are informed of the delivery routes and entry points. Contractors must adhere to pre-arranged storage areas, ensuring all materials and equipment are stored in good order. Waste, packaging, pallets, and stillages are to be removed promptly and correctly disposed of, reused, or recycled where practicable.\n   Site transport arrangements and vehicle movements as detailed by the client, Site access is via Existing main access from Ottringham Road until the new access if formed,\nparking will be in the designated area on site. The Principal Contractor is to be mindful that the\naccess to the site to ensure waiting transport is off Ottringham Road. The access road is narrow/busy residential street/restricted by parked cars in some areas;\ntherefore, all contractor parking will be provided on site, no parking is available outside\nof the construction site. PCL will arrange for access for emergency vehicles to be maintained at all times or alternative access will be implemented." }
];

window.SNIPPETS["CPP Section 3.6"] = [
  { title: "3.6 Material Storage", content: "Some materials may be delivered to and stored at an on-site in the designated areas.  These areas are to be fenced off by the contractor in a manner agreed with PCL. All materials and equipment should be stored in an orderly, stable, safe, and secure manner and at no time obstruct access routes around or through the site or the building plots. Stored materials must not reach an over-abundance or be allowed to clutter the site. Fuel/oil storage and refuelling points must have appropriate bund containment and be secured to prevent tampering. A spill kit must be located at each facility, and users suitably trained and drilled in the correct procedure in the event of a spillage. Chemicals must be stored in a secure leak-proof container or cabin, clearly marked, and kept under a strict control regime with easy reference to COSHH Sheets/MSDS. In any instances of poor housekeeping that create a safety or fire hazard, immediate action is required of the contractor(s) to clear away/make safe. Failure to act by the contractor(s) will lead PCL to arrange clearance of the area and charge the offending contractor(s). " }
];

window.SNIPPETS["CPP Section 3.7"] = [
  { title: "3.7 General Site Security Arrangements", content: "All persons entering the site must satisfy the requirements of the PCL onboarding process and be confirmed to have the correct level or competency required for their role. Visitors are to report to the site office and remain there until a suitable escort is arranged or site induction provided whichever is appropriate. The following steps have been taken to prevent unauthorised entry as far as possible:\nAll gates, doors, and windows are to be secured outside working hours.\nDuring working hours, Security personnel will man all open doors and gates controlling entry to the site. Outside working hours, private security will maintain watch and access controls on a 24/7 basis.\nSuitable hoardings or fencing will secure the site. Warning signs will be prominently displayed, with protected routes leading all visitors directly to the site office.\nContractors are to notify the PCL Manager when personnel have completed their site employment. \nAll contractors/visitors will sign and out as a mandatory requirement \nSecurity requirements will be reviewed and increased as the project develops.\nThe site will be secured to prevent unauthorised access, particularly by children and youg persons.\nVisitors to site must be notified to the PCL senior manager prior to their arrival. Only personnel approved by the PCL senior manager will be permitted entry to site. Authorised visitors will be directed to the site office and may not enter unaccompanied by an authorised person. Visitors must comply with the site rules included in Appendix D .\nDeliveries must be notified on the appropriate material delivery notification form/ticket. This also applies to temporary plant.\nMaterials and plant may only be removed from site with the authority of the PCL senior manager.\nPCL management must be kept fully informed of the names of all individuals working on site and must be given prior notification of their final dates for work on the project. Daily Labour and Plant Returns must be submitted each day.\nParking arrangements will be identified in the Traffic Management Plan and communicated in the site induction.\n " }
];

window.SNIPPETS["CPP Section 3.8"] = [
  { title: "3.7,a Clients Site Security requirements", content: "The Site security arrangements will be a combination of PCL policies and procedures and industry lead guidance such as the HSG 151 \" Protecting the Public - Your next Move\". Every part of the work area, so far as is reasonably practicable, will have its perimeter identified by suitable signs and fencing/hoarding, so its extent is readily identifiable. The perimeter fencing is to be installed to either of the following Gleeson specification drawings, TWD-928 Heras Fencing Detail (Option A) or TWD-905 Heras Fencing Detail (Option B) before commencing work on site.   " }
];

window.SNIPPETS["CPP Section 4.1"] = [
  { title: "4.1 Significant Hazards identified in Pre construction", content: "Significant hazards associated with the following work activities as identified in the PCI:\nWork at height\nExcavations\nUncontrolled structural collapse\nManual Handling\nTraffic management, pedestrian and vehicular traffic\nLive services\nDust, noise and vibration\nFire\nMaterials hazardous to health " }
];

window.SNIPPETS["CPP Section 5.1"] = [
  { title: "5.1 Roles & Responsibilities ", content: "\nContract Manager R&S – Lewis Peterson 07940 150485\nContract Manager GWKs – Dave Preston 07512 211908\nSite Supervisor – Vincent Collingwood 073614 430571\nCommercial Manager – Ben Plews 07802 731250\nMD – Josh Preston 07446 129547\nH&S Officer – Simon Archer 07487 615747\nFirst Aider - TBC\nTemporary works coordinator – TBC\nFire Safety Coordinator – TBC\nManagement of underground services works - TBC\n " }
];

window.SNIPPETS["CPP Section 5.2"] = [
  { title: "5.2 Safety Leadership & Worker Engagement", content: "Safety on this site is managed through effective planning, clear communication, and a shared commitment from all personnel to carry out work safely and responsibly. Safe working practices are an integral part of the job and form the foundation of how all site activities are undertaken. PCL will  carry out a daily briefing or toolbox talk to review the planned works, identify potential hazards, and agree on the safest method of delivery. These briefings also provide an opportunity for the team to raise concerns, share observations, and suggest improvements. Open and honest communication ensures that everyone has a voice in maintaining a safe working environment. All operatives have the authority to stop work immediately if unsafe conditions are identified. Any concerns raised will be reviewed without delay, and suitable corrective actions agreed and implemented before work recommences. No one will be criticised for taking action to prevent an incident — protecting people always takes priority over production. All plant, tools, and equipment are inspected daily, and any defects are reported immediately so that repairs or replacements can be arranged. Good housekeeping standards are maintained at all times to prevent slips, trips, and other avoidable hazards. A “clean as you go” approach is promoted to ensure work areas remain organised and safe throughout the day. Regular safety tours, walks, etc  are carried out by PCL to verify that safe systems of work are being followed, PPE is being used correctly, and access routes remain clear but not limited to. Where improvements are identified, they are communicated directly to the workforce and actioned promptly. Training and ongoing competency development are key parts of our approach. All operatives receive instruction relevant to their tasks, along with continuous support to reinforce safe behaviour and encourage personal responsibility. The working culture on site is based on mutual respect and accountability. Everyone is expected to look after themselves, their colleagues, and the wider working environment. Through careful planning, strong supervision, and clear communication, all work will be completed safely, efficiently, and to the highest standard. \n  Our goal is simple — that every person involved in the project finishes the day in the same condition they started " }
];

window.SNIPPETS["CPP Section 6.1"] = [
  { title: "6.1 Clients Health & Safety Goals", content: "The PCL will  liaise closely with the Client or their representative throughout the works. The PCL shall ensure this Construction Phase plan specific to this project is readily available on site, developed, adapted and amended where necessary. Amendments shall be made to the document as the works progress and site circumstances change. The PCL shall comply with all current Health and Safety Legislation, Approved Codes of practice and Industry guidance. \nThe PCL will ensure that the works are adequately supervised at all times. By a competent person of suitable training and experience,  designated as the Senior Manager, they will hold a minimum of the CITB SMSTS accreditation and first aid at work training. The named individual or a suitable deputy will always be present at the site in order to supervise the works and receive and implement instructions from the Client. The PCL shall ensure regular Health and Safety inspections and audits are undertaken throughout the contract and any comments or actions are implemented without delay. If at any time during the project PCL feel that they do not have sufficient information relating to the works being carried out, the senior manager will contact the Client, for  further information.  It is important all of those involved in the project understand the priorities for the project, the Clients key criteria for success are: Safety – it is critical that the project is delivered and operated with safety of paramount importance, this includes the safety of the construction workforce, general public and staff. ‘Home Safe- Everyone, Every day’ Sustainability and Environmental – the project is to be delivered to minimise its environmental impact to the surrounding area.\n " }
];

window.SNIPPETS["CPP Section 6.2"] = [
  { title: "6.2 Welfare Arrangements", content: "Welfare arrangements will be provided in accordance with the Construction (Design and Management) Regulations 2015 schedule 2. These welfare facilities will be maintained in a clean and tidy condition throughout the contract. The welfare facilities will be inspected weekly by the PCL senior manager or their nominee and any defects or issues reported and subsequently rectified. The welfare facilities will be located within the site compound area in an area that has little or no PPE conditions." }
];

window.SNIPPETS["CPP Section 6.3"] = [
  { title: "6.3 Permit To Work (PTW)", content: "Permits to work systems will be in place for the following construction activities: \n  Electrical Works\n  Works at Height\n  Lifting Operations\n  Excavation Works\n  Works which are classified as being in a confined space as per the definition in the The Confined Spaces Regulations 1997 and in line with L101" }
];

window.SNIPPETS["CPP Section 6.4"] = [
  { title: " 6.4 Working at Height near excavations & ground collapse", content: "All excavation activities will be properly planned, managed, and supervised to ensure that the works are carried out safely and without risk to any person. Excavations present significant hazards to both those working within them and those working nearby, and therefore all works will follow a strict sequence of preparation, inspection, and monitoring. All excavation works will be managed under the temporary works process and will be subject to a temporary works design. The extent of the design will be in accordance with company requirements for trenches and excavations and risk posed. No excavation shall commence until a suitable risk assessment and safe system of work have been developed and agreed by the PCL. Excavations will be inspected daily by a competent person and after any event that could affect stability, such as heavy rain or vibration. In addition, a formal weekly inspection will be recorded on by PCL. If any sign of ground movement or instability is observed, work will stop immediately, and the area will be made safe before work resumes. Before breaking ground, the area will be scanned for buried services, and all known services will be identified, marked, and protected. \n  Excavations must be properly supported or battered back to prevent collapse, with the design of support systems confirmed through the temporary works procedure. Any changes to the design, depth, or sequence of work must be reviewed before excavation continues. Edge protection will be installed on all open sides of excavations where a fall could occur. Guard rails and barriers will be located securely to control the on site ground hazards and where plant is operating adjacent to excavations, suitable barriers or stop blocks will be provided to prevent vehicles entering the excavation safe zone. Safe access and egress will be maintained at all times using secured ladders or proprietary stair units extending at least one metre above the landing point. Ladders must be fixed and inspected daily, and used for access only. All entry and exit points must remain clear and unobstructed. Excavated material and equipment will be risk assessed to confirm its storage point away from the edge of the excavation to prevent collapse or materials falling into the trench. Work areas must remain level, firm, and free from slip or trip hazards. Where work is required at the edge of an open excavation, operatives must work from stable ground and make use of trench boxes or working platforms with adequate edge protection. \n  All lifting operations near excavations will be carried out under a lifting plan, and no outriggers or heavy plant are to be positioned close to excavation edges unless ground stability has been confirmed and adequate support provided. Operatives engaged in excavation works will hold the appropriate Skills card and be briefed on the hazards and control measures before starting work. .Personal protective equipment including safety helmets, high-visibility clothing, gloves, and protective footwear must be worn at all times. Where dust or airborne contaminants are present, respiratory protection will be issued and worn. An emergency procedure will be in place to cover potential incidents such as trench collapse, falls, or medical emergencies. Emergency routes must remain clear at all times, and suitable rescue equipment will be available on site. " }
];

window.SNIPPETS["CPP Section 6.5"] = [
  { title: "6.5 Manual Handling", content: "The weight of brickwork and blockwork specified should be less than 20kgs. This is not to mean that they carry no risk The person undertaking the lift should always ensure that they can manage the load and be trained in methods such as T.I.L.E.  Large steelwork or retaining sheets must have suitable handling/movement risk assessments and a safe system of work in place. Kerb laying and paving slabs etc. require the use of mechanical aids. The prevalence of musculoskeletal disorders (MSDs) in the industry highlights the need for suitable and sufficient risk assessments to be undertaken for all aspects of manual handling. Where manual handling is considered, a detailed risk assessment (using the HSE MAC tool as a starting basis) must be carried out and documented. Steelwork, precast concrete sections, and items of plant will generally weigh more than 25kgs and require mechanical handling. Items of a significant weight should be marked with their weight and if asymmetrical, their centre of gravity and where appropriate provided with lifting attachments and identified lifting points. Task specific manual handling assessments for all tasks are to be incorporated with method statements/risk assessments. \n  Compliance with Manual Handling - HSE Guidance HSG149, Backs for the future, INDG Manual Handling Assessment Charts. (HSE website http://www.hse.gov.uk/msd/mac/index).Occupational health issues will be highlighted at site induction with more specific requirements identified in method statements and risk assessments setting out controls for these hazards. " }
];

window.SNIPPETS["CPP Section 6.6"] = [
  { title: "6.6 Vehicluar Movements", content: "The movement of vehicles, plant and deliveries to and from site will be strictly controlled to ensure the safety of both the workforce and the general public. A detailed Traffic Management Plan will be maintained and reviewed throughout the project to ensure that vehicle routes and pedestrian walkways are clearly defined and physically segregated wherever possible. All vehicle and pedestrian interfaces will be controlled using barriers, signs, and trained traffic marshals if so required. PCL may require logistics meetings to be held to coordinate deliveries, update access routes, and manage plant and vehicle movements in line with site progress. Where works are carried out adjacent to, or above, public areas, suitable exclusion zones will be established. Parking in the surrounding highway is restricted, and therefore there will only be on-site parking for vehicles. All delivery drivers will be briefed on the requirement to wear appropriate PPE at all times while outside their vehicles and to follow the instructions from the traffic management plan. Materials and equipment must be safely loaded and secured to prevent movement or load shedding during transit. \n  Deliveries such as floor plates and concrete panels must be clearly identified with lifting points and handled only with appropriate mechanical aids. Drivers operating HIAB or tail-lift equipment must be trained, competent, and authorised to use such equipment. A suitable lifting plan must be in place and approved by   " }
];

window.SNIPPETS["CPP Section 6.7"] = [
  { title: "6.7 Buried & Live Services", content: "The PCI includes details of below ground services stored on the Central Data Environment(CDE) this information is also appended in the CPP. This information is supplemented by physical surveys and construction records available for the site.\nAll excavation will be the subject of a risk assessment with a safe working method developed to define how the work should be carried out, along with control measures to minimise the risk of incident. A permit system will be used to ensure that appropriate control measures are implemented and maintained throughout. " }
];

window.SNIPPETS["CPP Section 6.8"] = [
  { title: "6.8 Dust, Noise & Vibration (DNV)", content: "Groundworks and excavation activities have the potential to create dust, noise and vibration (DNV) which, if uncontrolled, could present health risks to operatives and cause nuisance or disturbance to neighbouring properties and the surrounding environment. All such activities will therefore be managed and monitored to ensure DNV are kept to the lowest practicable level. Dust control measures will include the use of damping down with water, misting systems, and vacuum attachments on cutting or breaking tools where appropriate. The generation of dust must be avoided wherever possible, and where this cannot be achieved, suitable suppression or extraction systems must be used. Vacuum attachments or on-tool extraction will be fitted to equipment producing dust from materials such as concrete, blockwork or insulation. Decisions not to use such attachments must be justified within the task-specific risk assessment. Where dust creation is unavoidable, operatives will wear suitable Respiratory Protective Equipment (RPE) as identified within the risk assessment. As a minimum, this will be FFP3-rated protection, and wearers must have been trained in its correct use and Face Fit Tested. The use of RPE will be recorded, and test certification made available to site management. The activity must also take into consideration workers in close proximity and isolation measures must be used. Dust control will be particularly important during dry weather, when excavation, material movement or the loading and tipping of soil has a higher potential to create airborne dust. Damping down will be carried out at regular intervals using bowsers or fixed water supplies. Access roads and hardstanding areas will be kept damp and swept clean to reduce the spread of dust beyond the site boundary. Stockpiles will be kept to a minimum height and covered where practical to prevent wind-blown material.\nNoise control will also form part of daily planning for groundwork operations. Activities with the potential to create noise will be assessed to determine their likely impact and to identify measures to minimise disturbance. Where possible, low-noise equipment will be selected and maintained in good working condition. Noisy operations such as breaking, piling, or cutting will be programmed to take place during normal working hours and at times agreed with the PCL and the client. Operatives will be briefed on avoiding unnecessary revving, dropping of materials, or simultaneous operation of multiple noise-producing tools. Where excessive noise levels are identified, localised screening or temporary acoustic barriers may be used. The aim will always be to reduce noise exposure for operatives and minimise nuisance to the local community. Ear protection will be worn as specified in the task risk assessments, and noise monitoring may be carried out where high-risk operations continue for extended periods. Vibration control will apply to both hand-arm vibration (HAV) and ground-transmitted vibration affecting nearby structures. Groundworkers using percussive tools or vibrating equipment will use the correct tool for the task and limit exposure in line with safe working times. Where practicable, mechanical plant will be used to reduce the need for prolonged manual breaking. Vibration monitoring will be carried out during percussive operations to ensure that levels remain within acceptable limits, especially where the works are adjacent to public roads, buildings, or buried services. If vibration is found to be excessive, the work method will be reviewed, and alternative low-impact techniques will be adopted. \nShould vibration have the potential to affect neighbouring properties or utilities, PCL will liaise with the client and possibly adjacent landowners before starting work. Where necessary, works may be timed to limit disruption and regular inspections will be undertaken to confirm that no damage has occurred in line with local authority restrictions.  All dust, noise and vibration management arrangements will be reviewed as groundworks progress to ensure that control measures remain effective. Regular toolbox talks will reinforce the importance of good housekeeping, correct tool use, and adherence to agreed working hours. Through proper planning, supervision, and communication, all nuisance and exposure will be minimised for both the workforce and the public.\n " }
];

window.SNIPPETS["CPP Section 6.9"] = [
  { title: "6.9 Fire and emergency Arrangements", content: "Any hot work undertaken during groundwork activities, such as cutting, welding, or grinding of reinforcement, ducting, or metalwork, will be subject to a Hot Work Permit system. Hot work permits will be issued on a daily basis and closed out at the end of each shift. Hot work will cease one hour before the end of the working day to allow the work area to cool and to ensure post-activity fire watch monitoring can be completed. The area where hot works have taken place must be inspected during and after completion to confirm that no smouldering or ignition sources remain.\nThe use of oxy-acetylene equipment will not be permitted unless there is no suitable alternative. Where its use is approved, the contractor must demonstrate that suitable control measures and supervision are in place in conjunction with the hot work permit. All gas cylinders must be kept upright, fitted with flashback arrestors, and stored in a designated secure, well-ventilated area when not in use. Cylinders must be removed from the workface at the end of each shift and stored in the approved compound or taken off site. All groundworks involving cutting, welding, or other heat-generating processes must be planned and managed to prevent fire. Flammable materials such as timber shuttering, packaging, insulation, or formwork must be kept clear of hot work areas. The work area will be checked for combustibles before the task begins, and a fire extinguisher suitable for the materials in use must be available at the point of work. All activities on site must be carried out in full compliance with the project’s Fire risk assessment, with particular attention paid to the removal of flammable waste, redundant materials, and packaging. Storage areas must be kept tidy and segregated from hot work zones. Materials requiring fire retardant protection will be treated in accordance with the manufacturer’s guidance. Detailed method statements are required for all hot work operations, clearly defining the control measures to be implemented, including supervision, equipment checks, isolation of ignition sources, and emergency arrangements. Fire prevention and control measures will be reinforced through inductions, toolbox talks, and ongoing supervision. Operatives will be made aware of the nearest fire points, alarm call points, and assembly areas before commencing work. Regular inspections will be carried out by PCL to ensure that hot work activities are properly authorised, monitored, and recorded in accordance with site procedures.\n " }
];

window.SNIPPETS["CPP Section 6.10"] = [
  { title: "6.10 Materials Hazardous to Health", content: "All substances and materials used during ground working activities will be properly assessed and controlled before use. This includes products such as curing agents, concrete additives, fuels, bituminous compounds, jointing materials, formwork release agents, sealants, cleaning agents, and any other chemical-based or hazardous substances used in excavation, drainage, or foundation construction. All COSHH materials used on site will be subject to a current COSHH assessment, and the relevant Safety Data Sheet (SDS) will be available within the site safety file. The assessment will identify the hazards associated with the substance and define the control measures to be implemented, including safe handling methods, PPE requirements, and storage arrangements. All hazardous materials will be stored in bunded, lockable containers located within designated storage areas. These storage areas will be clearly identified, kept secure at all times, and equipped with suitable spill containment. Containers will remain sealed when not in use, and incompatible substances will be segregated to prevent adverse reactions. Operatives handling or applying products will be briefed on the relevant hazards and control measures through induction and task-specific toolbox talks. They will be familiar with the correct use of PPE, first aid measures, and the actions to take in the event of a spill or exposure. Where flammable or solvent-based materials are used, they will be stored within fire-rated cabinets or approved compounds, away from ignition sources and drainage channels. Quantities kept on site will be restricted to those required for the immediate task, and any waste or empty containers will be safely removed or disposed of at the end of each shift. \n  Storage and handling arrangements for COSHH products will be reviewed regularly by the PCL to confirm that control measures remain effective and that all substances are correctly labelled, secure, and accounted for. Any unlabelled, damaged, or out-of-date products will be removed from site immediately. The storage, and handling of COSHH products will be managed by the PCL to ensure safe working conditions, prevent pollution, and protect both personnel and the surrounding environment. " }
];

window.SNIPPETS["CPP Section 6.11"] = [
  { title: "6.11 Maintenance of Plant & Equipment", content: "All plant and equipment used/operated on site is hired from an approved hire company (apart from hand tools).\nMaintaining such plant and equipment is the legal responsibility of the hire company.\nAny defects, faults observed on site are immediately reported to PCL and the item of plant/equipment\nis taken out of use and the supplier is informed. Current test and examination and inspections records shall be retained and maintained as necessary.  \nWeekly plant inspections will be undertaken by plant operatives and recorded on PCL standard forms.    " }
];

window.SNIPPETS["CPP Section 6.12"] = [
  { title: "6.12 Contaminated Land", content: "During construction and enabling phases, PCL will implement appropriate control measures to protect all personnel involved in excavation and ground working operations. The first if which will be to study the PCI that has been provided prior to any breaking ground activities. \nAll personnel engaged in ground excavation will hold appropriate asbestos awareness certification. The workforce will remain vigilant for signs of unusual materials, odours, or staining that may indicate contamination. Any suspicious material discovered during excavation will be reported immediately to PCL, and the area will be isolated to prevent further disturbance.\nIf asbestos-containing materials (ACMs) or other hazardous substances are suspected or confirmed, PCL will contact a licensed specialist contractor to attend site to assess, sample, and remove the material in accordance with current requirements. The affected area will remain isolated until the specialist confirms that it is safe to continue work and the client will be contacted. PCL maintains a call-out agreement with a licensed environmental contractor who can provide immediate support for the identification, testing, and removal of contaminated material. All findings and actions taken will be recorded, and any additional control measures required will be implemented prior to recommencement of excavation. All contaminated soil, water, or material removed from site will be handled and disposed of in accordance with the approved waste management procedures and consignment documentation. Continuous monitoring will be carried out during excavation works to ensure that air quality and ground conditions remain safe throughout the construction phase.\nAlso identified in the PCI is a recommendation for gas protection measures in relation to carbon dioxide, the implications of this are for the specification of the Reinforced concrete floor slab and beam and block to meet the requirements of BS8485 this condition maybe superseded by building regulations consultation with the building regulations Principal Designer or qualified building inspector prior to construction to confirm.\n" }
];

window.SNIPPETS["CPP Section 6.13"] = [
  { title: "6.13 First Aid Arrangements", content: "Site first aid arrangements shall be explained to all persons during initial induction sessions i.e. fully stocked\n first aid kits; including eyewash stations are available in the site office. Welfare and first provisions will be provided and included in the site compound.  " }
];

window.SNIPPETS["CPP Section 6.14"] = [
  { title: "6.14 Work near high voltage power lines", content: " " }
];

window.SNIPPETS["CPP Section 7"] = [
  { title: "7.1 Monitoring", content: "Arrangements for monitoring Health, Safety and \n  Welfare throughout the Construction Phase of the Project will take the form of proactive inspections and audits. the frequency of these arrangements is detailed below in the table.The results of safety inspections and audits carried out will be circulated also as below and will be available on site for inspection by interested parties, along with details of all remedial action taken to remedy non-compliance. Inspectors/auditors shall require evidence of competence for individual employees carrying out works on site, particularly for plant operators and employees working on risk activities, e.g. working at height, working in excavations, working with live energy sources.\nInspectors/Auditors may request any Subcontractor’s accident book or other statutory records, registers, test certificates, notices etc to be made available for inspection." }
];

window.SNIPPETS["CPP Section 8"] = [
  { title: "8.1 Communication and Liaison", content: "PCL will Liaise with the Principal Designer (PD)  as and when required, meetings will be instructed by the clients. PCL will carry out monthly safety inspections of the site; these inspections will be open to the clients inclusion on prior notice. A copy of the inspection report will be issued to the client. PCL will be responsible for ensuring all Subcontractors prior to them being allowed to carry out any works on site, provide suitably developed risk and COSHH assessments and appropriately developed Method statements ensuring all sub-contractor operatives have access to and sign and date them to confirm that they are fully aware of the risks involved. PCL will arrange regular hazard briefings, coordination meetings and other such communications to circulate health and safety information to their contractors. Due to the site specific situations and locations liaison will be required with utility companies and, where necessary, neighbours/adjacent landowners/users. Additionally, PCL will liaise with the project team on any health and safety matters, collect and/or pass on all Health and Safety information to the Principal Designer for inclusion within the Health and Safety File. " }
];

window.SNIPPETS["CPP Section 9"] = [
  { title: "9.1 Site Rules", content: "SITE RULES\nAll Contractors’ employees, self-employed personnel and visitors must comply with the requirements of the Construction Phase Plan.\nAll workers must have undertaken an induction specific to the site they intend to work on prior to starting work \nAll site personnel MUST sign in and out on a daily basis. \nAll visitors or persons not indicted or unfamiliar to the due (due to changes) will wait at the site office for a PCL representative.  \nAll Contractors must comply with any local authority traffic management and environmental requirements.\nThe site is a hard hat area; safety helmets, safety footwear (steel toe cap and midsole protection), hi-vis vests or jackets, eye and hand protection are not mandatory they are task specific. Safety helmets/hi-vis must follow the format specified by PCL (details will be provided). \nOther appropriate personal protective equipment must be worn/used e.g. appropriate enhanced eye protection, safety harnesses, hearing protection, gloves etc., as identified in risk assessments.\nScaffolds including mobile towers must not be altered or adapted except by competent and authorised personnel. Ladders & stepladders may only be used for low-risk light duty work of short duration, where a safer alternative cannot be utilised, and a specific risk assessment is in place and communicated.\nAppropriate clothing must be worn; the wearing of shorts (including three quarter length trousers) or going bare above the waist is not permitted.\nAll holes, leading edges or openings creating a fall or trip hazard must be securely covered or fenced with warning signage where necessary. Loading bay barriers must be immediately replaced when loading out operations are complete. The removal or phased hand-over of any edge protection/guard rails must have prior agreement with PCL.\nNo alcohol or un-prescribed drugs are allowed on site. Personnel suspected of being under the influence of alcohol or drugs will be subject to disciplinary measures. Any operatives taking prescribed drugs, which may affect their performance, must inform site management. Random drugs and alcohol testing will be carried out on site. For cause testing may be carried out following an accident, as part of an accident investigation.\nDue care and consideration must always be given to local residents, office workers and members of the public, to ensure they are not exposed to any risk and inconvenience is minimal. Abusive language, wolf whistling or acts likely to cause offence are not permitted.\nAll dust, noise, vibration, and pollution shall be kept to a minimum with all measures taken to prevent nuisance arising from the carrying out of the works.\nAll type of gas cylinders must be stored according to Regulations. Details of the safe use, signage and storage of gas cylinders shall be incorporated into the fire safety and emergency plans for the site.\nGood housekeeping is fundamental in providing a safe environment. Waste must be cleared and stored only in designated areas and regularly removed. Access routes and means of escape must be always kept clear and free of tripping hazards with workplaces cleared and tidied as works progress throughout the day.\nVehicles and Plant must give visual and/or audible warning when reversing or manoeuvring with suitable CCTV reversing aids and/or be attended and under direction.\nHot work procedures are in operation. Permits can be obtained from PCL, no fires allowed on site for any reason. Fuel storage must be bunded, secured and with fire point with other flammables stored appropriately.\nMobile phones must be used in designated safe areas only Never while using ride on or operating machinery.\nElectric power tools must be 110v or cordless battery operated.\nPetrol driven plant can only be used only by prior arrangement.\nFood is to be consumed in Welfare canteen/Offices provided only.\nMisuse or abuse of any safety equipment or welfare facilities e.g. signage, fire extinguishers, toilets, lighting, etc., will not be tolerated. Urinating on site, apart from in the toilets provided, will lead to dismissal.\nOnly authorised/trained personnel may operate plant – All personnel shall be correctly trained, competent and in possession of appropriate Skill Card(s) for the work they are employed.\nThe site has a strict NO SMOKING policy – the designated smoking areas must be kept clean and tidy.\nUsers of plant and equipment must carry appropriate pre-use inspections – taking out of service any defective items.\nContractors must ensure their personnel adhere to the site rules, imposing retraining or disciplinary measures for non-compliance. PCL will dismiss personnel from the project for any persistent abuse of the Safety Rules.\n " }
];

window.SNIPPETS["CPP Section 10"] = [
  { title: "10.1 Design Changes during the Construction Phase", content: "PCL will report to the Client or their representative, if for any reason there is additional information required or a change to the scope of works. The Designer in charge of the designer change will assess the Health and Safety implications of any proposed design change, contract instructions or any eventuality which could impact on health and safety. The Principal Designer will be made aware of any significant health and safety risks or changes to programme or methods of working resulting from these changes. The Designer in charge of the design change will, take into account the general principles of prevention and any preconstruction information to eliminate risks to health and safety in the construction phase, maintenance phase or deconstruction phase. if it is not possible to eliminate the risks information will be provided by the designer to the Principal Designer (PD) in this case Gleesons." }
];

window.SNIPPETS["CPP Section 11.1"] = [
  { title: "11.1 Site Induction", content: "Site Induction\nAll personnel must attend the PCL site specific Induction prior to commencing work on site. Visitors, including delivery drivers, will be given a brief induction which will cover site health and safety issues they need to be aware of during their visit and requested to identify any health concerns they have which we may need to address. In addition, while on site, a responsible member of the team will accompany them.\nInduction will be carried out by a member of the management team and will cover the following subjects where applicable:\nConstruction Phase Plan\nRelevant Legislation\nSite Geography\nIdentification of Site Hierarchy\nSite rules\nFirst Aid Arrangements & Reporting of Accidents and “Near Miss” Incidents\nEnvironmental Requirements – noise, dust, vibration, pollution controls etc.\nInterface with Others/Care & Consideration of General Public\nInterface with other contractors\nPersonal Protective Equipment\nEmergency Preparedness and Response Plan\nSafety Equipment\nPlant, Vehicular routes and works in the vicinity of operating plant\nAccess and Egress\nScaffolding\nExcavations\nCOSHH\nElectricity\nHand Tools\nHousekeeping\nWelfare Facilities and Hygiene\nRisk Assessments and Method Statements\nDaily activity briefings\nTime outs for safety\nPermits to Work\nManual Handling (Musculo-skeletal disorders)\nTraffic Management\nLifting Operations\nDrugs and Alcohol Policy / testing regimes\nFit for work certificates\nSpecific hazards\nOccupational Health Concerns – Dust, fumes, HAVS, dermatitis, noise induced hearing loss, Weil’s disease, psittacosis, etc.\n(This list is not exhaustive and may be amended and built upon during the contract.)\n " }
];

window.SNIPPETS["CPP Section 11.2"] = [
  { title: "11.2 Toolbox Talks", content: "Contractors must undertake their own job specific training ensuring their personnel are fully aware of the contents of Method Statements and Risk Assessments and any subsequent updates thereafter through Daily Activity Briefings. Pre-start work and daily briefings will be undertaken for all site personnel, especially where routine works are affected by external issues, e.g. plant movements, weather and other interface concerns for more complex works such work or task briefings should be the norm. PCL or their Health and safety representative will require access to such training records both to verify the content and where necessary receive appropriate instruction on elements of the contractor’s work. A programme of regular \n  Toolbox Talks to include refresher/familiarisation training is to be undertaken by contractors, with evidence that Toolbox talks, and other identified safety training requirements are being undertaken. Contractors must practice “two-way communication” at all levels of toolbox talks or safety briefing enhancing worker engagement and developing a safety culture and pride in the job.\n " }
];

window.SNIPPETS["CPP Section 11.3"] = [
  { title: "Daily Activity Briefings", content: "These are to be carried out daily every morning prior to starting work by PCL & contractors. These briefings should last approximately 5/10 mins. The topics to be discussed should include the scope of works to be carried out, the safety and health hazards that are present, PPE requirements, as well as the good practices, lessons learned etc. from previous work activities; The briefings are to be recorded. \n " }
];

window.SNIPPETS["CPP Section 11.4"] = [
  { title: "Contractors", content: "All contractors will be required to produce proof of training for their employees prior to commencement of work on site. Contractors must demonstrate a commitment through the provision of training where necessary, leading to recognised skill training levels. Our goal is to ensure that every worker and supervisor has the requisite skills, knowledge, training, and experience in line with the CDM 2015 expectations.\nContractors must ensure that personnel are in possession of a valid card which reflects the skill/ability of the operative.\nAll other such training must be relevant to their responsibilities on this project; supervisors and managers should have the necessary health and safety training e.g. IOSH Managing/Supervising Safely and/or preferably the SMSTS 5 day managerial or supervisory health and safety training in addition to possessing appropriate CSCS card. A two-day SSSTS course is the minimum requirement accepted for site supervisors.\nPersonnel commencing on site without a recognised card must be able demonstrate they are working towards this objective – CSCS Health and Safety Test booked and followed up with the appropriate pass.\nAudits will be undertaken to ensure personnel are continuing working toward attaining appropriate card.\nAll such training must be relevant to their responsibilities on this project; supervisors and managers should have the necessary health and safety training commensurate with their additional responsibilities, e.g. first aiders, IPAF, temporary works, etc.\nAll contractors will be required to produce proof of training for their employees prior to commencement on site. Details will be relevant to their responsibilities on the project e.g. CITB recognised training schemes/qualifications: Construction Plant Operators Certification Scheme (CPCS) and Construction Skills Certification Scheme (CSCS).\nStatutory requirements for training/registration schemes e.g. Gas Safe (gas) and NRASWA (Streetworks) must be complied with. In addition all plant operators are required to be in possession of a current CPCS  record card respectively.\n(Safety Training cards retained by PCL)\n " }
];

window.SNIPPETS["CPP Section 12"] = [
  { title: "12.1 Waste Management", content: "All waste produced during the works will be managed in accordance with current environmental legislation and best practice. Site debris and surplus materials will be removed to a registered landfill or recycling facility, with all waste transfer notes completed and retained for record. Loads leaving site will be securely covered, and the site access road and adjacent highway will be kept clean and free from mud or debris at all times. A wheel wash or road sweeper will be used as required to maintain safe and clean road conditions. \n  A Site Waste Management Procedure will be in place detailing how waste will be segregated, recycled, and recorded. " },
  { title: "12.2 Surface Water Management", content: "All operations will follow the Surface Water Management Plan included in Appendix D to ensure that surface and groundwater are protected. Suitable measures will be established to prevent silt, concrete washout, fuel, or chemical runoff entering surface water drains or natural watercourses. Drainage protection controls such as silt traps, geotextile filters, and settlement tanks will be used where necessary. Any dewatering or pumping activities will be controlled to prevent water pollution and erosion.\n " },
  { title: "12.3 Contaminated Land", content: "Covered elsewhere in this document" },
  { title: "12.4 Asbestos & Hazardous Materials", content: "Covered elsewhere in this document" },
  { title: "12.5 Fuel & Oil Storage", content: "Covered elsewhere in this document" },
  { title: "12.5 Ecology and Protected Species", content: "The site is subject to ecological considerations highlighted within the Ecology Survey. \n  All works will be planned to avoid disturbance to local wildlife and protected habitats. Vegetation clearance will be minimised, and activities will be timed to avoid nesting bird seasons and other sensitive periods. Operatives will be briefed on ecological awareness to ensure that any sightings or potential issues are reported immediately and appropriate action is taken.\n " },
  { title: "12.6 Dust Noise & Vibration DNV", content: "Covered elsewhere in this document" },
  { title: "12.7 Traffic Management", content: "Covered elsewhere in this document" },
  { title: "12.8 Environmental Emergencies ", content: "Procedures will be in place to manage environmental incidents such as fuel spills, chemical leaks, or contaminated runoff. All such incidents will be reported immediately to PCL and recorded within the site log. \n  Emergency spill kits and containment materials will be kept on site, and all personnel will receive instruction on their location and use. Any incident involving environmental pollution will be investigated, and corrective action will be implemented to prevent recurrence.\n " },
  { title: "12.9 General Environmental Good Practice", content: "Good housekeeping will be maintained at all times to ensure that materials and waste are properly managed, storage areas remain secure, and the risk of pollution is minimised. The burning of waste materials will not be permitted under any circumstances. \n  All operatives will be encouraged to reduce unnecessary idling of plant and equipment to minimise emissions. Environmental awareness and respect for the surrounding area will be reinforced through inductions, toolbox talks, and supervision.\n " }
];

window.SNIPPETS["CPP Section 13"] = [
  { title: "13.1 Plant & Equipment Management", content: "All plant and equipment will be properly maintained, regularly inspected, and serviced in accordance with manufacturer recommendations. Records of all statutory inspections and test certificates will be retained on site within the Plant and Equipment Register. Plant will not be permitted to operate on site until all statutory inspections and safety checks have been completed and verified. Daily pre-use inspections will be carried out by the operator, and any defects identified will be reported immediately. Defective or unsafe equipment will be taken out of service until repairs are completed. All items of plant such as excavators, dumpers, rollers and compactors will only be operated by trained and competent personnel who hold the appropriate certification or operator card. Copies of competency cards (e.g. CPCS, NPORS) will be held on file by PCL. All plant will display clear identification showing ownership and inspection status. Drip trays and spill control measures will be provided for all refuelling areas to prevent leaks or fuel contamination to the ground or nearby watercourses. Only designated refuelling areas will be used. Mechanical equipment such as disc cutters and vibrating plate compactors will be inspected before each use, with particular attention to guarding, fuel lines and power leads. Cutting and grinding equipment will be fitted with appropriate dust suppression attachments where necessary. \n  Where plant is left unattended, ignition keys will be removed, and isolators or kill-switches applied to prevent unauthorised use. Mobile plant will be fitted with seat belts, reversing alarms, and flashing beacons. Pedestrian and plant routes will be clearly marked and maintained to prevent collisions and reduce interaction between operatives and moving machinery. All free-standing halogen lamps, or similar high-heat lighting systems, are prohibited from use due to fire risk. Task lighting will be limited to LED or other low-heat alternatives approved by the PCL. The use of mobile phones or similar devices is prohibited while operating plant or machinery. Drivers and operatives must not use phones, listen to music, or engage in any activity that may cause distraction while operating or supervising moving equipment.\n  All groundworking plant will be parked in designated compounds when not in use, with buckets lowered, parking brakes applied, and engines turned off. Refuelling and maintenance will be carried out by trained personnel using spill kits and drip trays as required. PCL will carry out regular inspections to confirm that plant and equipment are being used safely, maintained in good condition, and operated in line with site rules and this Construction Phase Plan. Through correct operation, inspection, and supervision, plant and equipment will be managed to ensure the safety of all personnel working on or near groundworking machinery. " }
];

window.SNIPPETS["CPP Section 14.1"] = [
  { title: "14.1 COSHH Assessments", content: "\nA COSHH assessment is required for all hazardous materials (as defined by the COSHH regulations) used on site. Safety Data Sheets (Chemical Hazard Information) must accompany all materials that are used and brought to site. A list of ALL materials/substances on site, whether hazardous or otherwise, must be produced by all parties (PCL and contractors); with COSHH assessments for any relevant materials/substances, which will indicate the type of material/substance, if they are hazardous and the quantity on site, the handling, storage, use and disposal arrangements for the substance and will be specific to the activity and location of proposed use. \nThese assessments will be given to PCL. All contractors are required to produce project specific COSHH assessments for all work involving hazardous substances and hazardous processes as defined in the COSHH regulations, i.e. welding, cutting, etc. These assessments must be submitted for approval and communicated to the workforce prior to the commencement of such work. Contractors must provide written evidence of this communication and consultation has been undertaken and training given to the operatives involved with such activities. The onus is on all contractors for total compliance with these requirements and any delays caused by non-compliance with these requirements will be the responsibility of the contractor concerned. The contractor will be responsible for the disposal arrangements of any COSHH materials.\n " }
];

window.SNIPPETS["CPP Section 14.2"] = [
  { title: "14.2 Health Surveillance", content: "All personnel will be advised at induction to provide information in confidence on their health, e.g. whether they are on any form of medication or are suffering any disability or phobia etc. Contractors are required to demonstrate that the following minimum occupational health arrangements are in place:\nEach contractor shall demonstrate the occupational health risks that they are likely to encounter and how they will deal with these. Likely requirements for health surveillance will include personnel exposed to Hand Arm Vibration Syndrome (HAVS), Noise Induced Hearing Loss and other defined statutory requirements e.g. lead or asbestos workers. Each contractor must demonstrate that they have systems and procedures in place to deal with health surveillance when identified in risk assessment. Where workers are exposed, management arrangements must be in place for the rehabilitation of these workers. Toolbox talks and other promotional materials on occupational health issues are to be used to improve the understanding of health risks to the workforce. Each contractor will monitor occupational sickness absence. \nThe contractor shall notify the Principal Contractor if any employees, Contractor or Sub-contractor's employees have, or develop a medical condition which the Principal Contractor should be aware of for Health & Safety reasons. The contractor shall ensure that all employees have occupational health arrangements / fit for work certificates in place. Safety Critical Workers, Operators of mobile plant, and those controlling the movement of mobile plant and vehicles, and specific roles such as scaffolders, etc., must have attended a health assessment within the last 12 months and be in possession of 'Fit to Work' certification. All other operatives must have attended suitable health assessments within the past three (3) years and be in possession of similar certification which must be presented prior to starting on site. Further advice can be sought via the HSE website: http://www.hse.gov.uk/. The contractor shall work to meet these commitments with immediate effect with guidance and information being provided as required by the Principal Contractor. Contractors are responsible for the health surveillance of their employees in accordance with legislative requirements. Where legislation / risk assessment requires health surveillance/screening for personnel, they must immediately advise these arrangements to PCL.\n " }
];

window.SNIPPETS["CPP Section 15"] = [
  { title: " 15.1 Provision/format of the Health & Safety File ", content: "Under the Construction (Design and Management) Regulations 2015, it is a requirement that a Health and Safety File is compiled for each project.\nAll contractors are required to contribute and provide information intended for the Health and Safety File as they complete their works. This information will be collated for file production and given to the Principal Contractor for eventual handover to the Client.\nThe Principal Designer has agreed the format of this file with the client and it will include:\nA brief description of the work carried out;\nAny hazards that have not been eliminated through the design and construction processes and how they have been addressed\nKey structural principles and safe working loads for floors and roofs.\nHazardous materials used\nInformation regarding the removal or dismantling of installed plant and equipment\nHealth and safety information about equipment provided for cleaning or maintaining the structure\nInformation and as-built drawings of the building, its plant and equipment.\nPCL will endovour to collate and deliver the file to the PD within 2 weeks of completion.  \n " }
];

window.SNIPPETS["CPP Section 16"] = [
  { title: "16.0 Accident and Incident Arrangements", content: "\n  The purpose of this section is to outline the Principal Contractor’s arrangements for the prevention, reporting, recording, and investigation of all accidents, incidents, dangerous occurrences, near misses and cases of occupational ill health that occur during the construction phase. These arrangements ensure compliance with the Construction (Design and Management) Regulations 2015 (Regulation 13), the Reporting of Injuries, Diseases and Dangerous Occurrences Regulations 2013 (RIDDOR) and the Health and Safety at Work etc. Act 1974.\n\n  All personnel and subcontractors working under the control of the Principal Contractor are required to comply with these arrangements. This includes but is not limited to all groundworks, excavation, plant operations, lifting, service installation and general construction activities.\n\n  Responsibilities:\n\n  Principal Contractor:\n  • Establish and maintain arrangements for the reporting, recording and investigation of all accidents and incidents.\n  • Maintain the site accident book and central incident register.\n  • Notify the HSE, Client and Principal Designer of all RIDDOR reportable events within statutory timescales.\n  • Coordinate and lead investigations into incidents and ensure corrective actions are implemented and communicated.\n  • Ensure appropriate first aid and emergency provisions are in place.\n  • Review incident data and trends to drive continual improvement.\n\n  Contractors and Subcontractors:\n  • Immediately report any accident, incident, near miss or unsafe act to the Principal Contractor’s Site Manager.\n  • Provide first aid and ensure any injured person receives appropriate medical attention.\n  • Preserve the scene of any serious or reportable incident until authorised by the Principal Contractor.\n  • Submit a written incident report within 24 hours of the event.\n  • Cooperate fully in all investigations and assist in implementing preventative actions.\n\nIn the event of an accident, incident, or near miss, all site personnel must take immediate action to ensure safety and compliance. Minor injuries requiring only first aid must be treated promptly and recorded in the site accident book, with details reported to the Site Supervisor on the same working day. Injuries requiring medical treatment or resulting in lost time must be reported immediately to the Site Manager, who will ensure the area is made safe and appropriate medical assistance arranged. In the event of a RIDDOR-reportable incident or dangerous occurrence, all work in the affected area must stop immediately. The scene must be preserved, and the Principal Contractor’s Site Manager or Health and Safety Advisor notified without delay. Any near misses or unsafe acts must also be made safe and reported to the Site Supervisor as soon as possible, normally on the same day. Cases of occupational ill health must be reported to the Site Manager or Health and Safety Manager within 24 hours of identification so that appropriate investigation and monitoring can be carried out\n\n  All incidents and near misses must be recorded in the Site Accident Register and reviewed weekly by site management. Findings will be discussed during coordination and safety meetings.\n\n  Investigation and Follow-Up:\n  The Principal Contractor’s Health and Safety Manager or other competent person will lead investigations into significant events. Investigations will identify immediate, underlying and root causes using recognised methods such as “5 Whys” or “Fishbone Analysis”. Corrective and preventive actions will be tracked through completion, and lessons learned will be communicated via toolbox talks and site safety briefings. Risk assessments and method statements will be reviewed where required.\n\n  RIDDOR Reporting:\n  The Principal Contractor is responsible for statutory reporting to the HSE. Reportable incidents include fatalities, specified injuries, over-seven-day incapacitations, dangerous occurrences and occupational diseases such as dermatitis or silicosis. All RIDDOR notifications and investigation outcomes will be shared with the Client and Principal Designer.\n\n  Communication and Training:\n  The accident and incident reporting process will be detailed during site induction and reinforced through regular toolbox talks. Safety alerts and bulletins will be issued following incidents to ensure lessons are shared across the workforce. Performance data and trends will be reviewed at regular safety meetings.\n\n  Records and Retention:\n  The following documents will be maintained on site:\n  – Site Accident Book\n  – Incident and near miss reports\n  – RIDDOR submissions and correspondence\n  – Investigation reports and supporting evidence\n  – Corrective action logs\n  – Toolbox talk records and safety bulletins\n  All records will be retained inline with PCL's company policy.\n  " }
];

